import { createContextHook } from '@universe-design/react-utilities';
import type { usePagination } from './usePagination';

const PaginationContext = createContextHook<ReturnType<typeof usePagination>>('PaginationContext', {
  strict: true,
});

export const PaginationContextProvider = PaginationContext.Provider;
export const usePaginationContext = PaginationContext.useContext;
